review_comments:
["`getRemoteCLIBin` assumes any non-'stable' quality uses the `code-insiders` binary. The repo has a distinct `exploration` quality (e.g. in test/sanity) which uses `code-exploration`, so SSH installs/execs will fail on exploration builds. Consider mapping known qualities (stable/insider/exploration) to the correct CLI binary name and normalizing any legacy values (e.g. 'insiders' -> 'insider') before building paths/URLs.

See below for a potential fix:
```
function normalizeQuality(quality: string | undefined): string | undefined {
	if (!quality) {
		return undefined;
	}

	const q = quality.toLowerCase();

	if (q === 'insiders') {
		return 'insider';
	}

	return q;
}

/** Install location for the VS Code CLI on the remote machine. */
function getRemoteCLIDir(quality: string): string {
	const normalizedQuality = normalizeQuality(quality);
	return normalizedQuality === 'stable' || !normalizedQuality ? '~/.vscode-cli' : `~/.vscode-cli-${normalizedQuality}`;
}
function getRemoteCLIBin(quality: string): string {
	const normalizedQuality = normalizeQuality(quality);
	let binaryName: string;

	switch (normalizedQuality) {
		case undefined:
		case 'stable':
			binaryName = 'code';
			break;
		case 'insider':
			binaryName = 'code-insiders';
			break;
		case 'exploration':
			binaryName = 'code-exploration';
			break;
		default:
			binaryName = 'code-insiders';
			break;
	}
```", "`_quality` currently falls back to `'insider'` when `productService.quality` is unset. Since the previous behavior always used the stable CLI paths/URL, this changes behavior for builds where `quality` is undefined and may start downloading/looking for the insiders CLI unexpectedly. If the intent is to preserve the old default, consider falling back to `'stable'` (or to `''` and let helpers treat it as stable) and/or explicitly normalizing supported quality values.", '## Pull request overview

Updates the SSH remote agent host startup path to select and install the correct VS Code CLI (stable vs non-stable) based on the running product’s `quality`, instead of always using the stable CLI.

**Changes:**
- Injects `IProductService` into `SSHRemoteAgentHostMainService` to read the current product `quality`.
- Computes remote CLI install directory/binary path from `quality` and uses it for both installation checks and agent-host startup.
- Uses `quality` when constructing the CLI download URL instead of hardcoding `stable`.



']

["`getRemoteCLIBin` assumes any non-'stable' quality uses the `code-insiders` binary. The repo has a distinct `exploration` quality (e.g. in test/sanity) which uses `code-exploration`, so SSH installs/execs will fail on exploration builds. Consider mapping known qualities (stable/insider/exploration) to the correct CLI binary name and normalizing any legacy values (e.g. 'insiders' -> 'insider') before building paths/URLs.

See below for a potential fix:
```
function normalizeQuality(quality: string | undefined): string | undefined {
	if (!quality) {
		return undefined;
	}

	const q = quality.toLowerCase();

	if (q === 'insiders') {
		return 'insider';
	}

	return q;
}

/** Install location for the VS Code CLI on the remote machine. */
function getRemoteCLIDir(quality: string): string {
	const normalizedQuality = normalizeQuality(quality);
	return normalizedQuality === 'stable' || !normalizedQuality ? '~/.vscode-cli' : `~/.vscode-cli-${normalizedQuality}`;
}
function getRemoteCLIBin(quality: string): string {
	const normalizedQuality = normalizeQuality(quality);
	let binaryName: string;

	switch (normalizedQuality) {
		case undefined:
		case 'stable':
			binaryName = 'code';
			break;
		case 'insider':
			binaryName = 'code-insiders';
			break;
		case 'exploration':
			binaryName = 'code-exploration';
			break;
		default:
			binaryName = 'code-insiders';
			break;
	}
```", "`_quality` currently falls back to `'insider'` when `productService.quality` is unset. Since the previous behavior always used the stable CLI paths/URL, this changes behavior for builds where `quality` is undefined and may start downloading/looking for the insiders CLI unexpectedly. If the intent is to preserve the old default, consider falling back to `'stable'` (or to `''` and let helpers treat it as stable) and/or explicitly normalizing supported quality values.", '## Pull request overview

Updates the SSH remote agent host startup path to select and install the correct VS Code CLI (stable vs non-stable) based on the running product’s `quality`, instead of always using the stable CLI.

**Changes:**
- Injects `IProductService` into `SSHRemoteAgentHostMainService` to read the current product `quality`.
- Computes remote CLI install directory/binary path from `quality` and uses it for both installation checks and agent-host startup.
- Uses `quality` when constructing the CLI download URL instead of hardcoding `stable`.



']

